# ANTI-PATTERN: Reactive agent that fails on ambiguity
class ReactiveScorer:
    def observe_delivery(self, ball):
        if ball.line == "yorker":
            return "defend"
        elif ball.line == "short":
            return "pull"
        else:
            return "block"  # Fails for slower balls, crossseam, unexpected angles

# BEST PRACTICE: Deliberative agent with memory and reasoning
class DeliberativeScorer:
    def __init__(self):
        self.match_history = {}
        self.bowler_profile = {}

    def observe_delivery(self, ball, bowler, situation):
        # Gather context
        recent_balls = self.match_history.get(bowler.name, [])
        bowler_strengths = self.bowler_profile.get(bowler.name, {})

        # Reason: consider delivery type, bowler history, match situation
        analysis = self._analyze(ball, bowler_strengths, situation)

        # Decide: select best action
        decision = self._select_best_action(analysis)

        # Remember: update history
        self.match_history[bowler.name] = recent_balls + [ball]
        return decision

    def _analyze(self, ball, bowler_strengths, situation):
        """Reason through multiple factors"""
        return {
            "delivery_type": ball.type,
            "bowler_effectiveness": bowler_strengths.get(ball.type, 0.5),
            "match_context": situation["required_run_rate"],
            "risk_tolerance": situation["wickets_lost"]
        }

    def _select_best_action(self, analysis):
        """Deliberate before acting"""
        if analysis["bowler_effectiveness"] > 0.7:
            return "defend"  # Respect good bowlers
        return "attack" if analysis["match_context"] > 5 else "accumulate"

# Production-scale agent with error handling and observability
import logging
from enum import Enum
from typing import Optional

class MatchPhase(Enum):
    POWERPLAY = "powerplay"
    MIDDLE = "middle_overs"
    DEATH = "death_overs"

class CricketAgent:
    def __init__(self, player_name: str, risk_tolerance: float = 0.5):
        self.player_name = player_name
        self.risk_tolerance = risk_tolerance
        self.runs_scored = 0
        self.balls_faced = 0
        self.memory = {}
        self.logger = logging.getLogger(f"agent_{player_name}")

    def observe(self, bowler_type: str, field_position: str, match_phase: MatchPhase) -> dict:
        """Safely observe environment"""
        try:
            state = {
                "bowler": bowler_type,
                "field": field_position,
                "phase": match_phase.value,
                "strike_rate": self.runs_scored / max(self.balls_faced, 1)
            }
            self.logger.info(f"Observed state: {state}")
            return state
        except Exception as e:
            self.logger.error(f"Observation failed: {e}")
            return {}

    def reason(self, state: dict) -> str:
        """Decide on action with bounded rationality"""
        if not state:
            return "defend"

        strike_rate = state.get("strike_rate", 0)
        phase = state.get("phase", "")

        # Logic with safety bounds
        if phase == "death_overs" and strike_rate < 1.2 and self.risk_tolerance > 0.7:
            return "attack"
        elif phase == "powerplay":
            return "aggressive" if self.risk_tolerance > 0.5 else "cautious"
        return "defend"

    def act(self, decision: str) -> bool:
        """Execute with error recovery"""
        valid_actions = ["attack", "defend", "aggressive", "cautious"]
        if decision not in valid_actions:
            self.logger.warning(f"Invalid action {decision}, defaulting to defend")
            decision = "defend"

        self.balls_faced += 1
        if decision in ["attack", "aggressive"]:
            self.runs_scored += 2  # Simplified
        else:
            self.runs_scored += 1

        self.logger.info(f"Action: {decision} | Runs: {self.runs_scored}")
        return True

    def step(self, bowler_type: str, field_position: str, match_phase: MatchPhase) -> bool:
        """Single agent loop with fault tolerance"""
        try:
            state = self.observe(bowler_type, field_position, match_phase)
            decision = self.reason(state)
            return self.act(decision)
        except Exception as e:
            self.logger.critical(f"Agent loop failed: {e}")
            return False

# Usage in production
if __name__ == "__main__":
    logging.basicConfig(level=logging.INFO)
    virat = CricketAgent("virat", risk_tolerance=0.8)

    # Simulate match
    virat.step("fast", "slip_cordon", MatchPhase.POWERPLAY)
    virat.step("spin", "deep_field", MatchPhase.MIDDLE)
    virat.step("yorker", "ring_field", MatchPhase.DEATH)

    print(f"Final runs: {virat.runs_scored}, Balls: {virat.balls_faced}")
